// n8n 2.x wraps webhook body inside $json.body — always unwrap
const raw  = $input.item.json;
const body = raw.body || raw;

return {
  id:          body.id || body._id || `alert-${Date.now()}`,
  timestamp:   body.timestamp || new Date().toISOString(),
  full_log:    body.full_log || body.message || '',
  location:    body.location || '',
  data:        body.data || {},
  rule: {
    id:          String(body.rule?.id || 'unknown'),
    description: body.rule?.description || '',
    level:       Number(body.rule?.level || 0),
    groups:      body.rule?.groups || []
  },
  agent: {
    id:   String(body.agent?.id || '000'),
    name: body.agent?.name || 'unknown-agent',
    ip:   body.agent?.ip || ''
  }
};

// PATH TRUE — MCP enrichment succeeded
const mcpResponse   = $input.item.json;
const enrichedAlert = mcpResponse.enriched_alert || {};
const originalAlert = enrichedAlert.original_alert || {};
const context       = enrichedAlert.context || {};

const ruleSection = context.rule_details?.success
  ? `\nRule Details:\n${JSON.stringify(context.rule_details.rule, null, 2)}`
  : '';

const occSection = (context.recent_occurrences != null)
  ? `\nRecent occurrences in last 24h: ${context.recent_occurrences}`
  : '';

const agentSection = context.agent_details?.success
  ? `\nAgent Status: ${context.agent_details.agent?.status}`
  : '';

const prompt =
`You are a senior cybersecurity analyst specializing in SIEM false positive detection.

ALERT DETAILS:
- Rule ID:          ${originalAlert.rule?.id}
- Rule Description: ${originalAlert.rule?.description}
- Alert Level:      ${originalAlert.rule?.level}
- Agent:            ${originalAlert.agent?.name} (${originalAlert.agent?.ip})
- Timestamp:        ${originalAlert.timestamp}

FULL LOG:
${originalAlert.full_log}

MCP CONTEXT:${ruleSection}${occSection}${agentSection}

Respond ONLY with valid JSON (no markdown, no extra text):
{
  "verdict": "false_positive" | "legitimate_threat" | "uncertain",
  "confidence": 0-100,
  "reasoning": "detailed explanation",
  "action": "ignore" | "investigate" | "escalate",
  "context_factors": ["factor1"],
  "rule_tuning_suggestion": null
}`;

return {
  alert_id:      originalAlert.id,
  rule_id:       String(originalAlert.rule?.id || 'unknown'),
  agent_name:    originalAlert.agent?.name,
  prompt_for_ai: prompt,
  mcp_error:     false
};

// PATH FALSE — MCP unavailable, use raw alert only
const alert = $input.item.json;

const prompt =
`Analyze this Wazuh alert (LIMITED CONTEXT — MCP unavailable):

Rule: ${alert.rule?.id} - ${alert.rule?.description}
Level: ${alert.rule?.level}
Agent: ${alert.agent?.name} (${alert.agent?.ip})
Log: ${alert.full_log}

Respond ONLY with valid JSON:
{
  "verdict": "false_positive" | "legitimate_threat" | "uncertain",
  "confidence": 0-100,
  "reasoning": "explanation",
  "action": "ignore" | "investigate" | "escalate",
  "context_factors": [],
  "rule_tuning_suggestion": null
}`;

return {
  alert_id:      alert.id,
  rule_id:       String(alert.rule?.id || 'unknown'),
  agent_name:    alert.agent?.name,
  prompt_for_ai: prompt,
  mcp_error:     true
};

// Attach the execution resume URL before persisting to DB.
// NOTE (n8n 2.1.x): $execution.resumeUrl returns the correct
// webhook-waiting/<executionId> URL without any suffix needed.
const data = $input.item.json;

return {
  ...data,
  resume_url:    $execution.resumeUrl,
  mcp_error_int: data.mcp_error ? 1 : 0
};

// n8n 2.x: the Wait node also wraps the resume POST body inside $json.body
const raw  = $input.item.json;
const body = raw.body || raw;

const VALID_VERDICTS = ['false_positive', 'legitimate_threat', 'uncertain'];
const VALID_ACTIONS  = ['ignore', 'investigate', 'escalate'];

const verdict    = VALID_VERDICTS.includes(body.verdict) ? body.verdict : 'uncertain';
const action     = VALID_ACTIONS.includes(body.action)   ? body.action  : 'investigate';
const confidence = Math.min(100, Math.max(0, Number(body.confidence) || 0));

return {
  alert_id:           String(body.alert_id || ''),
  ai_verdict:         verdict,
  ai_confidence:      confidence,
  ai_reasoning:       String(body.reasoning || ''),
  ai_action:          action,
  ai_rule_tuning:     body.rule_tuning_suggestion || null,
  ai_context_factors: Array.isArray(body.context_factors)
                      ? body.context_factors : []
};

// Reads everything from $input — Alternative C pattern.
// All fields (pending metadata + AI response) arrive from Fetch Pending from DB.
const d = $input.item.json;

if (!d || d.pending_id == null) {
  throw new Error(
    'No pending record found for alert_id: ' + (d?.alert_id || 'unknown') +
    '. Check that status = pending in pending_analysis.'
  );
}

// SQL literal for NULL produces the string "null" — normalise it back
const ruleTuning = (d.ai_rule_tuning &&
                    d.ai_rule_tuning !== '' &&
                    d.ai_rule_tuning !== 'null')
  ? d.ai_rule_tuning
  : null;

return {
  pending_id:   Number(d.pending_id),
  alert_id:     d.alert_id,
  rule_id:      String(d.rule_id || 'unknown'),
  agent_name:   String(d.agent_name || ''),
  mcp_enriched: !d.mcp_error,
  ai_response: {
    verdict:                d.ai_verdict,
    confidence:             Number(d.ai_confidence),
    reasoning:              d.ai_reasoning,
    action:                 d.ai_action,
    rule_tuning_suggestion: ruleTuning
  }
};
